mapper.insert:
MERGE INTO TB_BOX_IVT_IVB001_M ivb001
USING DUAL ON (ivb001.FNCN_BSNS_PBAN_NO = #{fncnBsnsPbanNo})
WHEN MATCHED THEN
UPDATE SET
    IIBS_LSMD_TS = CURRENT_TIMESTAMP
    
    ,FNCN_BSNS_PBAN_TTL_NM = #{fncnBsnsPbanTtlNm}
    
    ,FNCN_BSNS_PBAN_DCD = #{fncnBsnsPbanDcd}
    
    ,FNCN_BSNS_NM = #{fncnBsnsNm}
    
    
    ,PBAN_YMD = #{pbanYmd}
    
    
    ,PRDO_RCCG_YMD = #{prdoRccgYmd}
    
    
        ,RSPB_EMN = #{rspbEmn}
    
    
    ,RPRS_CNPL_CON = #{rprsCnplCon}
    
    ,PBAN_DTL_CON = #{pbanDtlCon}
    ,FILE_UNQ_NO = #{fileUnqNo}
    ,DEL_YN = #{delYn}
    ,IIBS_LSMD_ID = #{iibsLsmdId}
WHEN NOT MATCHED THEN
INSERT
(
    FNCN_BSNS_PBAN_NO
    
    ,FNCN_BSNS_PBAN_TTL_NM
    
    ,FNCN_BSNS_PBAN_DCD
    
    ,FNCN_BSNS_NM
    
    
    ,PBAN_YMD
    
    
    ,PRDO_RCCG_YMD
    
    
    , RSPB_EMN
    
    
    ,RPRS_CNPL_CON
    
    ,PBAN_DTL_CON
    ,FILE_UNQ_NO
    ,DEL_YN
    ,RGSR_NM
    ,IIBS_FRRG_TS
    ,IIBS_FRRG_ID
)
VALUES
(
    #{fncnBsnsPbanNo}
    
    ,#{fncnBsnsPbanTtlNm}
    
    ,#{fncnBsnsPbanDcd}
    
    ,#{fncnBsnsNm}
    
    
    ,#{pbanYmd}
    
    
    ,#{prdoRccgYmd}
    
    
    , #{rspbEmn}
    
    
    ,#{rprsCnplCon}
    
    ,#{pbanDtlCon}
    ,#{fileUnqNo}
    ,#{delYn}
    ,#{rgsrNm}
    ,CURRENT_TIMESTAMP
    ,#{iibsFrrgId}
)

MERGE INTO TB_BOX_IVT_IVB003_M ivb003
USING DUAL ON (ivb003.FNCN_BSNS_PBAN_NO = #{fncnBsnsPbanNo} AND ivb003.RGSN_SQN = #{rgsnSqn})
WHEN MATCHED THEN
UPDATE SET
    FNCN_BSNS_ENLS_FILD_UQN = #{fncnBsnsEnlsFildUqn}
    ,ORCY_FNCN_AMT = #{orcyFncnAmt}
    ,FNCN_BSNS_CHC_OPCM_CNT = #{fncnBsnsChcOpcmCnt}
    ,IIBS_LSMD_ID = #{iibsLsmdId}
    ,IIBS_LSMD_TS = CURRENT_TIMESTAMP
WHEN NOT MATCHED THEN
INSERT
(
    FNCN_BSNS_PBAN_NO
    ,FNCN_BSNS_ENLS_FILD_UQN
    ,RGSN_SQN
    ,ORCY_FNCN_AMT
    ,FNCN_BSNS_CHC_OPCM_CNT
    ,IIBS_FRRG_TS
    ,IIBS_FRRG_ID
)
VALUES
(
    #{fncnBsnsPbanNo}
    ,#{fncnBsnsEnlsFildUqn}
    ,#{rgsnSqn}
    ,#{orcyFncnAmt}
    ,#{fncnBsnsChcOpcmCnt}
    ,CURRENT_TIMESTAMP
    ,#{iibsFrrgId}
)

mapper.update:
UPDATE
    TB_BOX_IVT_IVB001_M
SET
    DEL_YN  = #{delYn}
WHERE
    FNCN_BSNS_PBAN_NO = #{fncnBsnsPbanNo}

UPDATE
    TB_BOX_IVT_IVB101_M
SET
    FNCN_BSNS_PGRS_SCD  = #{fncnBsnsPgrsScd}
WHERE
    FNCN_BSNS_RCIP_NO = #{fncnBsnsRcipNo}

mapper.insert:
MERGE INTO TB_BOX_IVT_COM_CD_D ccd
USING DUAL ON (ccd.COM_CD_ID = #{comCdId} AND ccd.GRP_CD_ID = #{grpCdId})
WHEN MATCHED THEN
UPDATE SET
    COM_CD_NM = #{comCdNm}
    ,AMNN_USER_ID = #{amnnUserId}
    ,AMNN_TS = CURRENT_TIMESTAMP
WHEN NOT MATCHED THEN
INSERT
(
    COM_CD_ID,
    GRP_CD_ID,
    COM_CD_NM,
    COM_CD_DESC,
    LNP_SQN,
    USE_YN,
    RGSN_USER_ID,
    RGSN_TS
)
VALUES
(
    #{comCdId}
    ,#{grpCdId}
    ,#{comCdNm}
    ,#{comCdDesc}
    ,#{lnpSqn}
    ,#{useYn}
    ,#{rgsnUserId}
    ,CURRENT_TIMESTAMP
)
